CREATE OR REPLACE FUNCTION public.normalize_phone_ar(phone_input text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
declare
    digits text;
begin
    if phone_input is null then
        return null;
    end if;

    digits := regexp_replace(phone_input, '\D', '', 'g');

    if length(digits) = 10 then
        return '549' || digits;
    end if;

    if digits like '549%' then
        return digits;
    end if;

    if digits like '54%' then
        return '9' || substr(digits,3);
    end if;

    return digits;
end;
$function$

CREATE OR REPLACE FUNCTION public.order_items_set_subtotal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.subtotal := coalesce(new.qty, 0) * coalesce(new.unit_price, 0);
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.purchase_order_items_set_subtotal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.subtotal := coalesce(new.qty, 0) * coalesce(new.unit_cost, 0);
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.set_customers_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.trg_customers_normalize_phone()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
    if new.phone is not null then
        new.phone := normalize_phone_ar(new.phone);
    end if;

    return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_order_item_stock()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_order_new public.orders%rowtype;
  v_available numeric(12,2);
  v_needed numeric(12,2);
begin
  -- Orden destino
  select *
    into v_order_new
    from public.orders
   where id = new.order_id;

  if v_order_new.id is null then
    raise exception 'La orden no existe';
  end if;

  -- INSERT
  if tg_op = 'INSERT' then
    v_needed := new.qty;

    select coalesce(sum(im.qty), 0)
      into v_available
      from public.inventory_movements im
     where im.product_id = new.product_id
       and im.variant_id is not distinct from new.variant_id
       and im.warehouse_id is not distinct from v_order_new.warehouse_id
       and im.point_of_sale_id is not distinct from v_order_new.point_of_sale_id;

    if v_available < v_needed then
      raise exception 'Stock insuficiente para el producto/variante. Disponible: %, solicitado: %',
        v_available, v_needed;
    end if;

    return new;
  end if;

  -- UPDATE
  if tg_op = 'UPDATE' then
    -- mismo producto/variante/order: validar solo aumento
    if old.product_id is not distinct from new.product_id
       and old.variant_id is not distinct from new.variant_id
       and old.order_id is not distinct from new.order_id then

      v_needed := new.qty - old.qty;

      if v_needed <= 0 then
        return new;
      end if;

      select coalesce(sum(im.qty), 0)
        into v_available
        from public.inventory_movements im
       where im.product_id = new.product_id
         and im.variant_id is not distinct from new.variant_id
         and im.warehouse_id is not distinct from v_order_new.warehouse_id
         and im.point_of_sale_id is not distinct from v_order_new.point_of_sale_id;

      if v_available < v_needed then
        raise exception 'Stock insuficiente para aumentar la cantidad. Disponible adicional: %, solicitado adicional: %',
          v_available, v_needed;
      end if;

      return new;
    end if;

    -- cambió producto / variante / orden: validar qty completa del nuevo destino
    v_needed := new.qty;

    select coalesce(sum(im.qty), 0)
      into v_available
      from public.inventory_movements im
     where im.product_id = new.product_id
       and im.variant_id is not distinct from new.variant_id
       and im.warehouse_id is not distinct from v_order_new.warehouse_id
       and im.point_of_sale_id is not distinct from v_order_new.point_of_sale_id;

    if v_available < v_needed then
      raise exception 'Stock insuficiente para el nuevo producto/variante. Disponible: %, solicitado: %',
        v_available, v_needed;
    end if;

    return new;
  end if;

  return new;
end;
$function$
